// ❌ BAD - regular function loses 'this' in a setTimeout callback
class NotificationService {
  send() {
    setTimeout(function() {
      this.log('sent'); // TypeError: this is undefined
    }, 1000);
  }
}

// ✅ GOOD - arrow function keeps 'this' from the class method
class NotificationService {
  send() {
    setTimeout(() => {
      this.log('sent'); // 'this' is the NotificationService instance
    }, 1000);
  }
}

// ❌ BAD - imperative loop with duplicated logic for each filter type
const activeUsers = [];
for (let u of users) { if (u.isActive) activeUsers.push(u); }
const premiumUsers = [];
for (let u of users) { if (u.isPremium) premiumUsers.push(u); }

// ✅ GOOD - higher-order filter with reusable predicate functions
const byActive = user => user.isActive;
const byPremium = user => user.isPremium;
const activeUsers = users.filter(byActive);
const premiumUsers = users.filter(byPremium);

// ❌ BAD - loose equality with coercion produces wrong results
function isProductInStock(quantity) {
  if (quantity == false) {   // matches 0, '', false, null, undefined
    return false;            // BUG: quantity=0 is valid but caught here
  }
}

// ✅ GOOD - strict equality and explicit checks
function isProductInStock(quantity) {
  if (quantity === 0) return false;  // only exact zero
  if (quantity == null) throw new Error('quantity required');
  return quantity > 0;
}

// ❌ BAD - without strict mode, typo creates accidental global
function saveUserProfile(userData) {
  userName = userData.name; // typo: should be userData.userName
  // silently creates global 'userName' - hard to find bug
}

// ✅ GOOD - strict mode catches the undeclared variable
'use strict';
function saveUserProfile(userData) {
  userName = userData.name; // ReferenceError: userName is not defined
}

// ❌ BAD - var in loop creates shared binding, all callbacks see final value
const handlers = [];
for (var i = 0; i < 3; i++) {
  handlers.push(() => console.log(i)); // all log 3
}

// ✅ GOOD - let creates a new binding per iteration
const handlers = [];
for (let i = 0; i < 3; i++) {
  handlers.push(() => console.log(i)); // logs 0, 1, 2
}

// ❌ BAD - spread is shallow, nested address is shared
const originalOrder = { id: 1, customer: { name: 'Alice', city: 'London' } };
const clonedOrder = { ...originalOrder };
clonedOrder.customer.city = 'Paris';
console.log(originalOrder.customer.city); // 'Paris' - original mutated!

// ✅ GOOD - structuredClone gives a true deep copy
const clonedOrder = structuredClone(originalOrder);
clonedOrder.customer.city = 'Paris';
console.log(originalOrder.customer.city); // 'London' - original safe
